+function sanitizeTerminalCells(value, fallback) {
+  const fallbackRaw = Number.isFinite(fallback) ? Math.trunc(fallback) : 1;
+  const safeFallback = Math.max(1, Math.min(0xffff, fallbackRaw));
+  if (!Number.isFinite(value)) return safeFallback;
+  const cells = Math.trunc(value);
+  if (cells <= 0) return safeFallback;
+  return Math.min(0xffff, cells);
+}
+function normalizeTerminalGeometry(rawCols, rawRows, fallbackCols, fallbackRows) {
+  return {
+    cols: sanitizeTerminalCells(rawCols, fallbackCols),
+    rows: sanitizeTerminalCells(rawRows, fallbackRows),
+  };
+}
