+function disablePaneOverlaySync(error, context = "pane overlay sync") {
+  if (!paneOverlaySyncFailed) {
+    paneOverlaySyncFailed = true;
+  }
+  try {
+    paneGhostDecay = null;
+    hideAlternateDockGhosts();
