+  console.error(`[ShowcaseDemo] Disabled pane overlay sync after ${context} failure:`, errorText);
+}
+
+function paneStateSnapshot() {
+  if (paneOverlaySyncFailed) return null;
+  if (typeof runner.paneLayoutState === "function") {
+    try {
+      return runner.paneLayoutState();
